namespace sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
    public required string Location { get; init; }
}

using sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Models;

namespace sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Models;
using sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Services;

namespace sv_5c31aa2b0b604c2fb4476bf36ebe434a.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Seeds = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new Shipment
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 26, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 9, 15, 0, TimeSpan.Zero), Description = "In transit to destination", Location = "Chicago, IL" },
            ]
        },
        ["TRK-1002"] = new Shipment
        {
            TrackingNumber = "TRK-1002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 12, 0, 0, TimeSpan.FromHours(-7)),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 24, 10, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 16, 0, 0, TimeSpan.Zero), Description = "Arrived at regional hub", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 8, 45, 0, TimeSpan.Zero), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 14, 20, 0, TimeSpan.Zero), Description = "Delivered — signed by recipient", Location = "San Francisco, CA" },
            ]
        },
        ["TRK-1003"] = new Shipment
        {
            TrackingNumber = "TRK-1003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 22, 0, 0, TimeSpan.Zero), Description = "Label created", Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        Seeds.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Models;

namespace sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Services;

/// <summary>
/// HTTP-based implementation used when the component runs on WebAssembly.
/// Calls the server-side API that wraps <see cref="IShipmentService"/>.
/// </summary>
public sealed class ShipmentServiceClient(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var encoded = Uri.EscapeDataString(trackingNumber);
        var response = await http.GetAsync($"api/shipments/{encoded}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

