var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddScoped<IShipmentService, ShipmentService>();

var app = builder.Build();

app.MapStaticAssets();

app.MapGet("api/shipments/{trackingNumber}", async (string trackingNumber, IShipmentService service, CancellationToken ct) =>
{
    var shipment = await service.GetShipmentAsync(trackingNumber, ct);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
});

app.MapRazorComponents<App>()

using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using sv_5c31aa2b0b604c2fb4476bf36ebe434a.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddScoped(sp =>
    new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ShipmentServiceClient>();

await builder.Build().RunAsync();

